func:
// Normalisation stricte – aucune décision
msg.timestamp = Date.now();
msg.priority = msg.priority || "NORMAL";

if (!msg.source) {
    if (msg.ui_event) msg.source = "UI";
    else if (msg.system_event) msg.source = "SYSTEM";
    else if (msg.vpiv) msg.source = "VPIV";
    else msg.source = "UNKNOWN";
}

msg.intent = msg.intent || "REQUEST";
return msg;

// Encode VPIV si absent
if (!msg.vpiv && msg.var && msg.value !== undefined) {
    msg.vpiv = {
        code: msg.var,
        value: msg.value
    };
}
return msg;

// Routage purement technique
if (msg.source === "UI") msg.topic = "PtoA";
else if (msg.source === "SYSTEM") msg.topic = "PtoA";
else if (msg.source === "VPIV") msg.topic = "AtoSP";
else msg.topic = "PtoSE";

return msg;
